import threading
from enum import Enum
from typing import Dict, Set, List, Optional
import time

class TransactionStatus(Enum):
    ACTIVE = "active"
    COMMITTED = "committed"
    ABORTED = "aborted"

class LockType(Enum):
    SHARED = "shared"  # Read lock
    EXCLUSIVE = "exclusive"  # Write lock

class Resource:
    def __init__(self, id: str, initial_value=None):
        self.id = id
        self.value = initial_value
        self.locks: Dict[LockType, Set[str]] = {
            LockType.SHARED: set(),
            LockType.EXCLUSIVE: set()
