class TransactionManager:
    def __init__(self):
        self.resources: Dict[str, Resource] = {}
        self.active_transactions: Dict[str, 'Transaction'] = {}
        self.lock_table: Dict[str, List[LockEntry]] = {}
        self.deadlock_detector = DeadlockDetector()

    def create_resource(self, id: str, value=None) -> None:
        if id not in self.resources:
            self.resources[id] = Resource(id, value)

    def start_transaction(self) -> 'Transaction':
        tx_id = f"TX_{threading.get_ident()}_{time.time()}"
        transaction = Transaction(tx_id, self)
        self.active_transactions[tx_id] = transaction
        return transaction

class Transaction:
    def __init__(self, id: str, manager: TransactionManager):
        self.id = id
        self.manager = manager
        self.status = TransactionStatus.ACTIVE
        self.read_set: Set[str] = set()
        self.write_set: Dict[str, Resource] = {}

    def read(self, resource_id: str) -> Optional[Resource]:
        if self.status != TransactionStatus.ACTIVE:
            raise ValueError("Transaction is not active")

        # Optimistic concurrency control
        return self.manager.get_resource(resource_id)

    def write(self, resource_id: str, value):
