            raise ValueError("Transaction is not active")

        # Optimize concurrency control
        resource = self.manager.get_resource(resource_id)
        self.write_set[resource_id] = resource

    def commit(self) -> None:
        if self.status == TransactionStatus.COMMITTED:
            return

        try:
            for res_id, _ in self.write_set.items():
                self.manager.lock_table[res_id].append(LockEntry(
                    tx_id=self.id,
                    lock_type=LockType.EXCLUSIVE
                ))

            # Check for deadlocks and conflicts
            if not self.deadlock_detector.detect_deadlock(self):
                raise TransactionAborted("Deadlock detected")

            # Apply writes
            for res_id, resource in self.write_set.items():
                resource.value = self.manager.get_resource(res_id).value

            self.status = TransactionStatus.COMMITTED

        except Exception as e:
            self.abort()

    def abort(self) -> None:
        if self.status == TransactionStatus.ACTIVE:
            # Release all locks
            for res_id in list(self.write_set.keys()):
                self.manager.unlock(self.id, res_id)

            self.status = TransactionStatus.ABORTED

