    def __init__(self, tx_id: str, lock_type: LockType):
        self.tx_id = tx_id
        self.lock_type = lock_type
        self.timestamp = time.time()

class DeadlockDetector:
    def __init__(self):
        self.cycle_counter = 0

    def detect_deadlock(self, transaction: Transaction) -> bool:
        # Perform graph-based deadlock detection
        if not self._has_cycle(transaction):
            return True

        # If a cycle is detected, abort the youngest transaction in the cycle
        self._abort_youngest_transaction(transaction)

        return False

    def _has_cycle(self, transaction: Transaction) -> bool:
        self.cycle_counter += 1
        timestamp = time.time()

        for res_id in transaction.write_set.keys():
            # Check if there's a waiting lock on this resource
            if not self._check_waiting_locks(res_id):
