            # If the cycle counter is the same, we've detected a deadlock
            return True

        return False

    def _check_waiting_locks(self, res_id: str) -> bool:
        locks = set()

        for lock in self.manager.lock_table[res_id]:
            if lock.tx_id == self.cycle_counter:
                locks.add(lock)

        return len(locks) > 0

    def _abort_youngest_transaction(self, transaction):
